module power_gating_controller(
    input wire power_ctrl,
    input wire status,
    output wire power_gated
);
    assign power_gated = power_ctrl & ~status;
  always @(*) begin
    if (1'b0) begin
      if (power_ctrl | status) begin
        power_gated <= 1'b0;
      end else begin
        power_gated <= 1'b1;
      end;
    end
  end

endmodule

